#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, m;
int fa[100005];
int dep[100005];
int son[100005];
int siz[100005];
int top[100005];
int id[100005];
vector <int> e[100005];
struct Tree {
	int Left, Right;
	int add, sum;
};
Tree tr[400005];
void build (int id, int Left, int Right) {
	tr[id].Left = Left;
	tr[id].Right = Right;
	if (Left == Right) {
		return;
	}
	build (id * 2, Left, (Left + Right) / 2);
	build (id * 2 + 1, (Left + Right) / 2 + 1, Right);
	return ;
}
void dfs1 (int u, int Fa, int Dep) {
	fa[u] = Fa;
	dep[u] = Dep;
	siz[u] = 1;
	int maxx = 0;
	for (auto v : e[u]) {
		if (v == Fa) {
			continue;
		}
		dfs1 (v, u, Dep + 1);
		siz[u] += siz[v];
		if (maxx < siz[v]) {
			son[u] = v;
			maxx = siz[v];
		}
	}
	return ;
}
void dfs2 (int u, int Fa) {
	top[u] = Fa;
	id[u] = ++id[0];
	if (!son[u]) {
		return;
	}
	dfs2 (son[u], Fa);
	for (auto v : e[u]) {
		if (fa[u] == v || son[u] == v) {
			continue;
		}
		dfs2 (v, v);
	}
	return ;
}
void push_down (int id) {
	tr[id * 2].add += tr[id].add;
	tr[id * 2 + 1].add += tr[id].add;
	tr[id * 2].sum += (tr[id * 2].Right - tr[id * 2].Left + 1) * tr[id].add;
	tr[id * 2 + 1].sum += (tr[id * 2 + 1].Right - tr[id * 2 + 1].Left + 1) * tr[id].add;
	tr[id].add = 0;
	return ;
}
void update (int id, int Left, int Right) {
	if (tr[id].Right < Left || tr[id].Left > Right) {
		return ;
	}
	if (tr[id].Left >= Left && tr[id].Right <= Right) {
		tr[id].sum += tr[id].Right - tr[id].Left + 1;
		tr[id].add++;
		return ;
	}
	push_down (id);
	update (id * 2, Left, Right);
	update (id * 2 + 1, Left, Right);
	tr[id].sum = tr[id * 2].sum + tr[id * 2 + 1].sum;
	return ;
}
int query (int id, int x) {
	if (tr[id].Right < x || tr[id].Left > x) {
		return 0;
	}
	if (tr[id].Left == tr[id].Right) {
		return tr[id].sum;
	}
	push_down (id);
	return query (id * 2, x) + query (id * 2 + 1, x);
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n >> m;
	for (int i = 1; i < n; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back (y);
		e[y].push_back (x);
	}
	dfs1 (1, 0, 1);
	dfs2 (1, 1);
	build (1, 1, n);
	while (m--) {
		char c;
		int x, y;
		cin >> c >> x >> y;
		if (c == 'P') {
			while (top[x] != top[y]) {
				if (dep[top[x]] < dep[top[y]]) {
					swap (x, y);
				}
				update (1, id[top[x]], id[x]);
				x = fa[top[x]];
			}
			if (dep[x] > dep[y]) {
				swap (x, y);
			}
			update (1, id[x] + 1, id[y]);
		} else {
			if (fa[x] == y) {
				cout << query (1, id[x]) << '\n';
			} else {
				cout << query (1, id[y]) << '\n';
			}
		}
	}
	return 0;
}
